/**
 * 조회조건저장
 */
scwin.setValue = function (e) {
  if (ed_cargoDate1.getValue() > ed_cargoDate2.getValue() || ed_vehclDate1.getValue() > ed_vehclDate2.getValue()) {
    $c.win.alert($p, "조회 기간이 잘못설정 되었습니다.");
    return;
  }
  const {
    cargoCidx,
    vehclCidx
  } = ds_cond.getRowJSON(0);
  if (cargoCidx == 0 || vehclCidx == 0) {
    $c.win.alert($p, "영업소가 선택되지 않았습니다.");
    return;
  }

  // 20171122 조회기간 한달이내만 검색가능하게 변경
  const startDate = new Date($c.date.formatDate($p, ed_cargoDate1.getValue(), "date"));
  const endDate = new Date($c.date.formatDate($p, ed_cargoDate2.getValue(), "date"));
  if (scwin.isOverOneMonth(startDate, endDate)) {
    $c.win.alert($p, "조회기간을 한달 이내로 설정 해 주세요.").then(() => {
      ed_cargoDate2.focus();
    });
    return;
  }
  let {
    hdoIdx: cargoHdidx,
    bhoIdx: cargoBhidx,
    offIdx: cargoOfcidx
  } = dma_comComboCargo.getJSON();
  let {
    hdoIdx: vehclHdidx,
    bhoIdx: vehclBhidx,
    offIdx: vehclOfcidx
  } = dma_comComboVehcl.getJSON();
  ds_cond.setCellData(0, "cargoHdidx", cargoHdidx);
  ds_cond.setCellData(0, "cargoBhidx", cargoBhidx);
  ds_cond.setCellData(0, "cargoOfcidx", cargoOfcidx);
  ds_cond.setCellData(0, "vehclHdidx", vehclHdidx);
  ds_cond.setCellData(0, "vehclBhidx", vehclBhidx);
  ds_cond.setCellData(0, "vehclOfcidx", vehclOfcidx);
  $c.sbm.execute($p, sbm_cond);
};

